body.script:
//
  // =========================================================================
  // CONFIGURASI UTAMA DEPLOYMENT (PENTING!)
  // =========================================================================
  const APP_VERSION = "qurbanku-2026-06-27-datepicker-setoran-v12";
  // Ubah IS_PREVIEW ke false jika Anda akan mem-publish aplikasi ke Blogger Live.
  const IS_PREVIEW = false; 
  const DEFAULT_GAS_URL = "https://script.google.com/macros/s/AKfycbwbmHjkY5cAlZEhKwn33m1mrIMOqLLp9bFHJO3wX7w0OKCLK1X4RaXXhWu6HwUKbnm0/exec";
  const BOOTSTRAP_GAS_URLS = [
    DEFAULT_GAS_URL,
    "https://script.google.com/macros/s/AKfycbwbmHjkY5cAlZEhKwn33m1mrIMOqLLp9bFHJO3wX7w0OKCLK1X4RaXXhWu6HwUKbnm0/exec"
  ];
  let activeGasUrl = localStorage.getItem("qurbankuGasUrl") || BOOTSTRAP_GAS_URLS[0] || "";

  // =========================================================================
  // DATA DUMMY MODEL (LOCAL FALLBACK / PREVIEW MODE)
  // =========================================================================
  let localDB = {
    tahap: [
      { id: "T1", nama: "Qurban 1447 H / 2026 M", status: "Aktif" },
      { id: "T2", nama: "Qurban 1446 H / 2025 M", status: "Nonaktif" }
    ],
    kelompok: [
      { id: "K1", nama: "Kelompok Sapi Al-Fatih", tipe: "Sapi", target: 21000000 },
      { id: "K2", nama: "Kelompok Kambing A", tipe: "Kambing", target: 3000000 }
    ],
    anggota: [
      { id: "A1", nama: "Ahmad Sulaiman", whatsapp: "08123456789", kelompok_id: "K1", target_saving: 3000000, pin: "1234" },
      { id: "A2", nama: "Budi Santoso", whatsapp: "08139876543", kelompok_id: "K1", target_saving: 3000000, pin: "1234" },
      { id: "A3", nama: "Hj. Aminah", whatsapp: "08571234567", kelompok_id: "K2", target_saving: 3000000, pin: "1234" },
      { id: "A4", nama: "H. Dimyati (Admin)", whatsapp: "08111111111", kelompok_id: "K1", target_saving: 3000000, pin: "admin2026" }
    ],
    setoran: [
      { id: "D1", anggota_id: "A1", tanggal: "2026-01-10", jumlah: 250000, bulan: 1, recorded_by: "H. Dimyati", catatan: "Setoran ke-1" },
      { id: "D2", anggota_id: "A1", tanggal: "2026-02-12", jumlah: 250000, bulan: 2, recorded_by: "H. Dimyati", catatan: "Setoran ke-2" },
      { id: "D3", anggota_id: "A2", tanggal: "2026-01-11", jumlah: 500000, bulan: 1, recorded_by: "H. Dimyati", catatan: "Langsung 2 bulan" }
    ],
    pengaturan: [
      { key: "admin_pin", value: "admin2026" }
    ]
  };

  // =========================================================================
  // STATE DAN CONFIG GLOBAL
  // =========================================================================
  let appState = {
    user: null, // Berisi object user yang login {role: 'admin'|'shohibul', data: userObj}
    currentTab: "dashboard",
    activeLoginTab: "admin",
    depositPage: 1,
    depositPageSize: 10,
    settings: {},
    data: {
      tahap: [],
      kelompok: [],
      anggota: [],
      setoran: []
    }
  };

  // =========================================================================
  // INITIALIZATION & LIFECYCLE
  // =========================================================================
  function removeDuplicateAppRoots() {
    const roots = Array.from(document.querySelectorAll("#qurbanku-app-root"));
    if (roots.length <= 1) return;
    roots.slice(0, -1).forEach(root => root.remove());
  }

  window.addEventListener("DOMContentLoaded", () => {
    removeDuplicateAppRoots();
    document.documentElement.setAttribute("data-qurbanku-version", APP_VERSION);
    console.log("QurbanKu version:", APP_VERSION);
    const versionBadge = document.getElementById("qurbanku-version-badge");
    if (versionBadge) versionBadge.innerText = APP_VERSION;
    // Inisialisasi library lucide icons
    if (window.lucide) {
      lucide.createIcons();
    }
    // Setup dropdowns
    populateBulanDropdown();
    // Tarik Data
    syncWithCloud();
  });

  function showLoading(show, title = "Mengambil Data...", subtitle = "Menghubungkan ke server cloud...") {
    const loader = document.getElementById("loading-screen");
    document.getElementById("loading-text").innerText = title;
    document.getElementById("loading-subtext").innerText = subtitle;
    if (show) {
      loader.classList.remove("opacity-0", "pointer-events-none");
    } else {
      loader.classList.add("opacity-0", "pointer-events-none");
    }
  }

  // =========================================================================
  // NETWORK SYNC LOGIC (GAS INTEGRATION)
  // =========================================================================
  function normalizeCloudData(response) {
    const source = response.data || response;
    const tahaps = source.tahap || source.tahaps || [];
    const groups = source.kelompok || source.groups || [];
    const participants = source.anggota || source.participants || [];
    const deposits = source.setoran || source.deposits || [];

    return {
      tahap: tahaps.map(t => ({
        id: t.id,
        nama: t.nama || t.name || "",
        status: t.status || "Aktif",
        updatedAt: Number(t.updatedAt || 0)
      })),
      kelompok: groups.map(g => ({
        id: g.id,
        nama: g.nama || g.name || "",
        tipe: g.tipe || g.type || "Sapi",
        target: Number(g.target || g.targetTotal || 0),
        tahapId: g.tahapId || "",
        updatedAt: Number(g.updatedAt || 0)
      })),
      anggota: participants.map(a => ({
        id: a.id,
        nama: a.nama || a.name || "",
        whatsapp: a.whatsapp || "",
        pin: a.pin || "1234",
        kelompok_id: a.kelompok_id || a.groupId || "",
        target_saving: Number(a.target_saving || a.targetAmount || 3000000),
        tahapId: a.tahapId || "",
        updatedAt: Number(a.updatedAt || 0)
      })),
      setoran: deposits.map(d => ({
        id: d.id,
        tanggal: d.tanggal || d.date || "",
        anggota_id: d.anggota_id || d.participantId || "",
        jumlah: Number(d.jumlah || d.amount || 0),
        bulan: Number(d.bulan || 1),
        recorded_by: d.recorded_by || d.recordedBy || "",
        catatan: d.catatan || d.note || "",
        tahapId: d.tahapId || "",
        updatedAt: Number(d.updatedAt || 0)
      }))
    };
  }

  function applyCloudSettings(response) {
    appState.settings = response.settings || appState.settings || {};
    if (appState.settings.cloudUrl && /^https:\/\/script\.google\.com\/macros\/s\/.+\/exec$/.test(appState.settings.cloudUrl)) {
      activeGasUrl = appState.settings.cloudUrl.trim();
      localStorage.setItem("qurbankuGasUrl", activeGasUrl);
    }
  }

  function setCloudIndicator(status, text) {
    const indicatorDot = document.getElementById("cloud-indicator-dot");
    const indicatorText = document.getElementById("cloud-indicator-text");
    if (!indicatorDot || !indicatorText) return;
    if (status === "online") {
      indicatorDot.className = "w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse";
      indicatorText.innerText = text || "Online (Live Cloud)";
    } else if (status === "preview") {
      indicatorDot.className = "w-2.5 h-2.5 rounded-full bg-amber-500 animate-pulse";
      indicatorText.innerText = text || "Simulasi (Lokal)";
    } else {
      indicatorDot.className = "w-2.5 h-2.5 rounded-full bg-red-500";
      indicatorText.innerText = text || "Error (Gagal Sinkron)";
    }
  }

  function getActiveGasUrl() {
    return (activeGasUrl || DEFAULT_GAS_URL || "").trim();
  }

  function getCandidateGasUrls() {
    const urls = [localStorage.getItem("qurbankuGasUrl"), activeGasUrl, ...BOOTSTRAP_GAS_URLS]
      .filter(Boolean)
      .map(url => url.trim())
      .filter(url => /^https:\/\/script\.google\.com\/macros\/s\/.+\/exec$/.test(url));
    return [...new Set(urls)];
  }

  function requestCloud(params = {}, forcedUrl = "") {
    return new Promise((resolve, reject) => {
      const gasUrl = (forcedUrl || getActiveGasUrl()).trim();
      if (!gasUrl || gasUrl.includes("PASTE")) {
        reject(new Error("URL Google Apps Script belum diisi."));
        return;
      }

      const callbackName = "qurbankuCallback_" + Date.now() + "_" + Math.floor(Math.random() * 100000);
      const script = document.createElement("script");
      const timeout = setTimeout(() => {
        cleanup();
        reject(new Error("Koneksi Google Apps Script timeout."));
      }, 30000);

      function cleanup() {
        clearTimeout(timeout);
        delete window[callbackName];
        if (script.parentNode) script.parentNode.removeChild(script);
      }

      window[callbackName] = (response) => {
        cleanup();
        if (response && response.status === "error") {
          reject(new Error(response.message || "Google Apps Script mengembalikan error."));
          return;
        }
        resolve(response || {});
      };

      const query = new URLSearchParams({ ...params, callback: callbackName, cache: Date.now().toString() });
      script.onerror = () => {
        cleanup();
        reject(new Error("Script JSONP Google Apps Script gagal dimuat."));
      };
      script.src = `${gasUrl}?${query.toString()}`;
      document.body.appendChild(script);
    });
  }

  function requestCloudFromCandidates(params = {}) {
    const urls = getCandidateGasUrls();
    let index = 0;

    function tryNext(lastError) {
      if (index >= urls.length) {
        throw lastError || new Error("Tidak ada URL Google Apps Script yang bisa dihubungi.");
      }
      const url = urls[index++];
      return requestCloud(params, url)
        .then(response => {
          activeGasUrl = url;
          localStorage.setItem("qurbankuGasUrl", url);
          return response;
        })
        .catch(tryNext);
    }

    return tryNext();
  }

  function syncWithCloud() {
    showLoading(true, "Sinkronisasi Cloud...", "Mengambil data terbaru dari Google Sheets...");

    if (IS_PREVIEW) {
      // Mode Simulasi: Gunakan data mockup local
      setTimeout(() => {
        appState.data = JSON.parse(JSON.stringify(localDB));
        setCloudIndicator("preview");
        showToast("Koneksi Lokal Berhasil (Mode Preview)", "info");
        afterDataLoaded();
        showLoading(false);
      }, 800);
    } else {
      // Mode Live: Gunakan JSONP agar stabil saat ditempel di Blogger.
      requestCloudFromCandidates({ action: "getData" })
        .then(response => {
          if (response.status === "success") {
            applyCloudSettings(response);
            appState.data = normalizeCloudData(response);
            setCloudIndicator("online");
            showToast("Data Tersinkronisasi dengan Google Sheet", "success");
            afterDataLoaded();
          } else {
            throw new Error(response.message || "Gagal mengambil data cloud.");
          }
        })
        .catch(err => {
          console.error("Gagal menarik data:", err);
          setCloudIndicator("error");
          showToast("Gagal koneksi ke Google Sheet. Data lokal tidak dipakai agar perangkat tidak terpisah.", "error");
          appState.data = { tahap: [], kelompok: [], anggota: [], setoran: [] };
          afterDataLoaded();
        })
        .finally(() => {
          showLoading(false);
        });
    }
  }

  function sendCloudWrite(action, payload) {
    showLoading(true, "Menyimpan Perubahan...", "Mengirim data ke database cloud...");
    if (IS_PREVIEW) {
      return new Promise((resolve) => {
        setTimeout(() => {
          // Logika simulasi penyimpanan lokal
          const id = "MOCK_" + Date.now();
          payload.id = id;
          if (action === "saveTahap") appState.data.tahap.push(payload);
          if (action === "saveKelompok") appState.data.kelompok.push(payload);
          if (action === "saveAnggota") appState.data.anggota.push(payload);
          if (action === "saveSetoran") appState.data.setoran.push(payload);

          showToast("Perubahan berhasil disimpan secara lokal!", "success");
          afterDataLoaded();
          showLoading(false);
          resolve({ status: "success", id: id });
        }, 600);
      });
    } else {
      const requestPayload = JSON.stringify({ action: action, data: payload });
      return requestCloud({ action: "sync", data: requestPayload })
      .then((response) => {
        if (response.status !== "success") {
          throw new Error(response.message || "Server tidak mengonfirmasi penyimpanan.");
        }
        applyCloudSettings(response);
        appState.data = normalizeCloudData(response);
        afterDataLoaded();
        showLoading(false);
        showToast("Data tersimpan dan tersinkron ke Google Sheet.", "success");
        return response;
      })
      .catch(err => {
        console.error("Gagal menyimpan data:", err);
        showLoading(false);
        showToast("Gagal menyimpan data ke cloud. Perubahan tidak disimpan lokal.", "error");
        throw err;
      });
    }
  }

  function afterDataLoaded() {
    populateShohibulSelect();
    populateGroupSelect();
    populateParticipantDropdownInSetoran();

    // Jika user sudah masuk, render ulang visualisasi dashboard & rekap
    if (appState.user) {
      renderAllContent();
    }
  }

  // =========================================================================
  // LOGIN & AUTENTIKASI UTAMA
  // =========================================================================
  function switchLoginTab(role) {
    appState.activeLoginTab = role;
    const tabAdmin = document.getElementById("tab-login-admin");
    const tabPeserta = document.getElementById("tab-login-peserta");
    const formAdmin = document.getElementById("form-login-admin");
    const formPeserta = document.getElementById("form-login-peserta");

    if (role === "admin") {
      tabAdmin.className = "flex-1 py-2 text-xs font-bold rounded-xl bg-white text-slate-950 shadow-sm transition duration-200";
      tabPeserta.className = "flex-1 py-2 text-xs font-semibold text-slate-500 hover:text-slate-900 rounded-xl transition duration-200";
      formAdmin.classList.remove("hidden");
      formPeserta.classList.add("hidden");
    } else {
      tabAdmin.className = "flex-1 py-2 text-xs font-semibold text-slate-500 hover:text-slate-900 rounded-xl transition duration-200";
      tabPeserta.className = "flex-1 py-2 text-xs font-bold rounded-xl bg-white text-slate-950 shadow-sm transition duration-200";
      formAdmin.classList.add("hidden");
      formPeserta.classList.remove("hidden");
    }
  }

  function handleLoginSubmit(event, role) {
    event.preventDefault();
    showLoading(true, "Memverifikasi Kredensial...", "Memvalidasi sandi akses Anda...");

    setTimeout(() => {
      if (role === "admin") {
        const userVal = document.getElementById("login-admin-user").value.trim();
        const passVal = document.getElementById("login-admin-pass").value.trim();

        // Cari admin dari database anggota jika dia terdaftar, atau fallback default
        const defaultPIN = "admin2026";

        if (userVal.toLowerCase() === "admin" && passVal === defaultPIN) {
          loginSuccess("admin", { nama: "Administrator", id: "ADMIN" });
        } else {
          // Coba cari dari data anggota
          const matchedAdmin = appState.data.anggota.find(a => 
            a.nama.toLowerCase().includes("admin") && a.pin === passVal
          );
          if (matchedAdmin) {
            loginSuccess("admin", matchedAdmin);
          } else {
            loginFail();
          }
        }
      } else {
        const userId = document.getElementById("login-peserta-select").value;
        const userPin = document.getElementById("login-peserta-pass").value.trim();

        const matchedUser = appState.data.anggota.find(a => a.id === userId && a.pin === userPin);
        if (matchedUser) {
          loginSuccess("shohibul", matchedUser);
        } else {
          loginFail();
        }
      }
    }, 500);
  }

  function loginSuccess(role, userObj) {
    appState.user = { role: role, data: userObj };

    // Update UI Tampilan Sesi
    document.getElementById("header-user-display").innerText = userObj.nama;
    document.getElementById("header-user-role").innerText = `Sesi ${role === "admin" ? "Pengurus" : "Shohibul"}`;

    // Atur visibilitas kelas CSS berbasis role
    const rootEl = document.getElementById("qurbanku-app-root");
    if (role === "shohibul") {
      rootEl.classList.add("role-shohibul");
    } else {
      rootEl.classList.remove("role-shohibul");
    }
    updateRoleNavigation();

    // Sembunyikan form login, tampilkan dashboard
    document.getElementById("login-screen").classList.add("hidden");
    document.getElementById("main-app-layout").classList.remove("hidden");

    // Sinkronisasi data ulang dan render
    switchTab("dashboard");
    showToast(`Selamat datang kembali, ${userObj.nama}!`, "success");
    showLoading(false);
  }

  function loginFail() {
    showLoading(false);
    showToast("Verifikasi gagal! Periksa kembali Username dan PIN Anda.", "error");
  }

  function handleLogout() {
    showConfirm("Konfirmasi Keluar", "Apakah Anda yakin ingin keluar dari sistem?", () => {
      appState.user = null;
      document.getElementById("qurbanku-app-root").classList.remove("role-shohibul");
      document.getElementById("login-screen").classList.remove("hidden");
      document.getElementById("main-app-layout").classList.add("hidden");
      showToast("Sesi login Anda telah berakhir.", "info");
    });
  }

  // =========================================================================
  // VIEW CONTROLLER & TAB SWITCHING
  // =========================================================================
  function isShohibulSession() {
    return appState.user && appState.user.role === "shohibul";
  }

  function getAllowedTabs() {
    return isShohibulSession() ? ["dashboard", "rekap"] : ["dashboard", "tahap", "kelompok", "anggota", "setoran", "rekap", "pengaturan"];
  }

  function updateRoleNavigation() {
    const dashboardLabel = document.querySelector("#nav-dashboard span");
    const rekapLabel = document.querySelector("#nav-rekap span");
    if (dashboardLabel) dashboardLabel.innerText = isShohibulSession() ? "Dashboard Anggota" : "Dashboard Utama";
    if (rekapLabel) rekapLabel.innerText = isShohibulSession() ? "Rekap Setoran Saya" : "Rekapitulasi Tabungan";
  }

  function switchTab(tabId) {
    const allowedTabs = getAllowedTabs();
    if (!allowedTabs.includes(tabId)) {
      tabId = "dashboard";
    }
    appState.currentTab = tabId;

    // Dapatkan semua seksi tab
    const tabs = ["dashboard", "tahap", "kelompok", "anggota", "setoran", "rekap", "pengaturan"];
    tabs.forEach(t => {
      const el = document.getElementById(`tab-${t}`);
      if (el) {
        if (t === tabId) el.classList.remove("hidden");
        else el.classList.add("hidden");
      }

      // Atur status aktif pada tombol navigasi sidebar
      const navBtn = document.getElementById(`nav-${t}`);
      if (navBtn) {
        const adminClass = ["tahap", "kelompok", "anggota", "setoran", "pengaturan"].includes(t) ? " admin-only" : "";
        if (t === tabId) {
          navBtn.className = `flex items-center gap-3.5 px-4 py-3 rounded-xl text-xs font-semibold transition bg-emerald-800 text-white w-full${adminClass}`;
        } else {
          navBtn.className = `flex items-center gap-3.5 px-4 py-3 rounded-xl text-xs font-semibold transition text-emerald-100 hover:bg-emerald-900/50 w-full${adminClass}`;
        }
      }
    });
    updateRoleNavigation();

    // Update Header Text
    const titleEl = document.getElementById("header-title");
    const subtitleEl = document.getElementById("header-subtitle");

    if (tabId === "dashboard") {
      titleEl.innerText = isShohibulSession() ? "Dashboard Anggota" : "Dashboard Utama";
      subtitleEl.innerText = isShohibulSession() ? "Ringkasan Tabungan Pribadi" : "Ringkasan Arisan & Qurban";
    } else if (tabId === "tahap") {
      titleEl.innerText = "Periode Qurban";
      subtitleEl.innerText = "Manajemen Arisan Aktif";
    } else if (tabId === "kelompok") {
      titleEl.innerText = "Kelompok Qurban";
      subtitleEl.innerText = "Daftar Sapi & Kambing";
    } else if (tabId === "anggota") {
      titleEl.innerText = "Daftar Shohibul";
      subtitleEl.innerText = "Anggota Keluarga Besar";
    } else if (tabId === "setoran") {
      titleEl.innerText = "Mutasi Tabungan";
      subtitleEl.innerText = "Catatan Transaksi Keuangan";
    } else if (tabId === "rekap") {
      titleEl.innerText = isShohibulSession() ? "Rekap Setoran Saya" : "Buku Rekapitulasi";
      subtitleEl.innerText = isShohibulSession() ? "Riwayat Pembayaran Pribadi" : "Arsip Pembayaran Tabungan";
    } else if (tabId === "pengaturan") {
      titleEl.innerText = "Integrasi Cloud";
      subtitleEl.innerText = "Konfigurasi Google Sheets";
    }

    renderAllContent();

    // Jika mobile, otomatis tutup menu sidebar setelah di-klik
    const sidebar = document.getElementById("app-sidebar");
    if (!sidebar.classList.contains("-translate-x-full")) {
      toggleMobileMenu();
    }
  }

  function toggleMobileMenu() {
    const sidebar = document.getElementById("app-sidebar");
    const backdrop = document.getElementById("sidebar-backdrop");

    if (sidebar.classList.contains("-translate-x-full")) {
      sidebar.classList.remove("-translate-x-full");
      backdrop.classList.remove("hidden");
    } else {
      sidebar.classList.add("-translate-x-full");
      backdrop.classList.add("hidden");
    }
  }

  // =========================================================================
  // DROPDOWN & DYNAMIC SELECT GENERATOR
  // =========================================================================
  function populateBulanDropdown() {
    const select = document.getElementById("deposit-bulan");
    select.innerHTML = "";
    for (let i = 1; i <= 12; i++) {
      const opt = document.createElement("option");
      opt.value = i;
      opt.innerText = `Bulan Pertemuan Ke-${i}`;
      select.appendChild(opt);
    }
  }

  function populateShohibulSelect() {
    const select = document.getElementById("login-peserta-select");
    select.innerHTML = "<option value=''>-- Pilih Nama Anda --</option>";

    const sortedAnggota = sortByNameAsc(appState.data.anggota);
    sortedAnggota.forEach(a => {
      const opt = document.createElement("option");
      opt.value = a.id;
      opt.innerText = a.nama;
      select.appendChild(opt);
    });
  }

  function populateGroupSelect() {
    const select = document.getElementById("participant-group");
    select.innerHTML = "<option value=''>-- Tanpa Kelompok --</option>";

    appState.data.kelompok.forEach(g => {
      const opt = document.createElement("option");
      opt.value = g.id;
      opt.innerText = `${g.nama} (${g.tipe})`;
      select.appendChild(opt);
    });
  }

  function populateParticipantDropdownInSetoran() {
    const select = document.getElementById("deposit-participant");
    select.innerHTML = "<option value=''>-- Pilih Anggota --</option>";

    const sorted = sortByNameAsc(appState.data.anggota);
    sorted.forEach(a => {
      const opt = document.createElement("option");
      opt.value = a.id;
      opt.innerText = a.nama;
      select.appendChild(opt);
    });
  }

  function suggestTargetPrice() {
    const type = document.getElementById("group-type").value;
    const targetInput = document.getElementById("group-target");
    if (type === "Sapi") {
      targetInput.value = 21000000; // Standar Sapi 7 Orang x 3.000.000
    } else {
      targetInput.value = 3000000; // Kambing 1 orang
    }
  }

  // =========================================================================
  // RENDERING DATA & LOGIC PRESENTASI
  // =========================================================================
  function renderAllContent() {
    renderDashboard();
    renderTahap();
    renderKelompok();
    renderParticipants();
    renderDeposits();
    renderRekap();
    renderSettings();
  }

  function formatRupiah(number) {
    return new Intl.NumberFormat("id-ID", {
      style: "currency",
      currency: "IDR",
      minimumFractionDigits: 0
    }).format(number);
  }

  function parseMoneyInput(value) {
    return Number(String(value || "").replace(/\D/g, "")) || 0;
  }

  function formatNumberGroup(value) {
    const cleanNumber = String(value || "").replace(/\D/g, "");
    return cleanNumber ? new Intl.NumberFormat("id-ID").format(Number(cleanNumber)) : "";
  }

  function formatMoneyInput(input) {
    input.value = formatNumberGroup(input.value);
  }

  function sortByNameAsc(items) {
    return [...items].sort((a, b) => String(a.nama || "").localeCompare(String(b.nama || ""), "id-ID", { sensitivity: "base", numeric: true }));
  }

  function getParticipantTotalSaving(anggotaId) {
    return appState.data.setoran
      .filter(d => d.anggota_id === anggotaId)
      .reduce((sum, d) => sum + Number(d.jumlah), 0);
  }

  function getParticipantDeposits(anggotaId) {
    return appState.data.setoran
      .filter(d => d.anggota_id === anggotaId)
      .sort((a, b) => Number(a.bulan) - Number(b.bulan) || parseDepositDate(a.tanggal) - parseDepositDate(b.tanggal));
  }

  function getLatestActiveMonth() {
    return Math.max(0, ...appState.data.setoran.map(d => Number(d.bulan) || 0));
  }

  function renderMemberDashboard() {
    const containerStats = document.getElementById("dashboard-stats");
    const containerGroups = document.getElementById("dashboard-group-progress");
    const personalBox = document.getElementById("personal-status-box");
    const cardDetails = document.getElementById("personal-card-details");
    const sectionTitle = document.querySelector("#tab-dashboard h3");

    const member = appState.user.data;
    const group = appState.data.kelompok.find(g => g.id === member.kelompok_id);
    const activeStage = appState.data.tahap.find(t => t.status === "Aktif")?.nama || "Tahap Aktif";
    const deposits = getParticipantDeposits(member.id);
    const totalPaid = deposits.reduce((sum, d) => sum + Number(d.jumlah || 0), 0);
    const paidMonths = new Set(deposits.map(d => Number(d.bulan))).size;
    const latestMonth = getLatestActiveMonth();
    const dueMonths = Math.max(0, latestMonth - paidMonths);
    const monthlyInstallment = Number(appState.settings.monthlyInstallment || 150000);
    const target = Number(member.target_saving || group?.target || monthlyInstallment * 12 || 0);
    const progress = target > 0 ? Math.min(Math.round((totalPaid / target) * 100), 100) : 0;
    const groupType = group ? group.tipe : "Mandiri";
    const latestDeposit = deposits[deposits.length - 1];

    containerStats.innerHTML = `
      <div class="relative overflow-hidden bg-gradient-to-br from-emerald-600 via-emerald-700 to-teal-800 text-white p-5 rounded-2xl shadow-sm space-y-3">
        <div class="absolute -right-8 -top-8 w-28 h-28 rounded-full bg-white/10"></div>
        <span class="text-[10px] text-emerald-100 font-bold uppercase tracking-wider">Jumlah Setoran Anda</span>
        <h4 class="text-2xl font-extrabold relative">${formatRupiah(totalPaid)}</h4>
        <p class="text-[10px] text-emerald-50 flex items-center gap-1.5 relative"><i class="fa-solid fa-circle-check"></i> ${paidMonths} dari 12 bulan tercatat</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-rose-100 shadow-xs space-y-3">
        <span class="text-[10px] text-rose-400 font-bold uppercase tracking-wider">Tunggakan Sampai Bulan Aktif</span>
        <h4 class="text-2xl font-extrabold ${dueMonths > 0 ? "text-rose-600" : "text-emerald-700"}">${dueMonths} Bulan</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1.5"><i class="fa-solid fa-wallet"></i> ${formatRupiah(dueMonths * monthlyInstallment)}</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-slate-200/80 shadow-xs space-y-3">
        <span class="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Jenis Kelompok</span>
        <h4 class="text-xl font-extrabold text-slate-900 truncate" title="${group ? group.nama : "Mandiri"}">${groupType}</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1.5"><i class="fa-solid fa-people-group"></i> ${group ? group.nama : "Belum masuk kelompok"}</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-slate-200/80 shadow-xs space-y-3">
        <span class="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Tahap Ke / Periode</span>
        <h4 class="text-sm font-extrabold text-emerald-700 truncate" title="${activeStage}">${activeStage}</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1.5"><i class="fa-solid fa-calendar-days"></i> Bulan aktif B${latestMonth || "-"}</p>
      </div>
    `;

    if (sectionTitle) {
      sectionTitle.innerHTML = `<i class="fa-solid fa-sparkles text-emerald-600"></i> Ringkasan Tabungan ${member.nama}`;
    }

    const recentRows = deposits.slice(-6).reverse().map(d => `
      <div class="flex items-center justify-between gap-3 rounded-xl border border-slate-100 bg-white px-4 py-3">
        <div>
          <p class="text-xs font-extrabold text-slate-900">B${Number(d.bulan) || "-"} - ${formatDateShortId(parseDepositDate(d.tanggal)) || d.tanggal || "Tanpa tanggal"}</p>
          <p class="text-[10px] text-slate-400 font-semibold">Dicatat oleh ${d.recorded_by || "Pengurus"}</p>
        </div>
        <span class="text-xs font-extrabold text-emerald-700 whitespace-nowrap">${formatRupiah(Number(d.jumlah || 0))}</span>
      </div>
    `).join("");

    containerGroups.innerHTML = `
      <div class="md:col-span-2 rounded-2xl border border-emerald-100 bg-gradient-to-br from-white to-emerald-50/70 p-5 space-y-5">
        <div class="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-3">
          <div>
            <p class="text-[10px] uppercase tracking-wider font-bold text-emerald-600">Progress Personal</p>
            <h4 class="text-lg font-extrabold text-slate-950">${member.nama}</h4>
            <p class="text-xs text-slate-500 mt-1">${group ? group.nama : "Mandiri"} - ${groupType}</p>
          </div>
          <div class="px-3 py-2 rounded-xl bg-white border border-emerald-100 text-right">
            <p class="text-[10px] font-bold uppercase text-slate-400">Setoran Terakhir</p>
            <p class="text-xs font-extrabold text-slate-900">${latestDeposit ? `B${latestDeposit.bulan}` : "Belum ada"}</p>
          </div>
        </div>
        <div class="space-y-2">
          <div class="flex justify-between text-[11px] font-bold text-slate-500">
            <span>${formatRupiah(totalPaid)}</span>
            <span>${progress}% dari target ${formatRupiah(target)}</span>
          </div>
          <div class="h-3 w-full overflow-hidden rounded-full bg-emerald-100">
            <div class="h-full rounded-full bg-gradient-to-r from-emerald-500 to-teal-500" style="width:${progress}%"></div>
          </div>
        </div>
        <div class="grid grid-cols-2 sm:grid-cols-4 gap-3">
          <div class="rounded-xl bg-white border border-slate-100 p-3"><p class="text-[10px] text-slate-400 font-bold uppercase">Target</p><p class="text-xs font-extrabold text-slate-900">${formatRupiah(target)}</p></div>
          <div class="rounded-xl bg-white border border-slate-100 p-3"><p class="text-[10px] text-slate-400 font-bold uppercase">Bulanan</p><p class="text-xs font-extrabold text-slate-900">${formatRupiah(monthlyInstallment)}</p></div>
          <div class="rounded-xl bg-white border border-slate-100 p-3"><p class="text-[10px] text-slate-400 font-bold uppercase">Terbayar</p><p class="text-xs font-extrabold text-slate-900">${paidMonths} Bulan</p></div>
          <div class="rounded-xl bg-white border border-slate-100 p-3"><p class="text-[10px] text-slate-400 font-bold uppercase">Tunggakan</p><p class="text-xs font-extrabold ${dueMonths > 0 ? "text-rose-600" : "text-emerald-700"}">${dueMonths} Bulan</p></div>
        </div>
      </div>
    `;

    cardDetails.innerHTML = recentRows || `<div class="text-center py-8"><p class="text-xs font-bold text-slate-700">Belum ada setoran tercatat</p><p class="text-[10px] text-slate-400 mt-1">Setoran yang dicatat pengurus akan muncul di sini.</p></div>`;
    personalBox.classList.remove("hidden");
    personalBox.querySelector("h3").innerHTML = `<i class="fa-solid fa-receipt text-emerald-600"></i> Riwayat Setoran Terbaru`;
  }

  // --- DASHBOARD RENDERING ---
  function renderDashboard() {
    if (isShohibulSession()) {
      renderMemberDashboard();
      return;
    }

    const containerStats = document.getElementById("dashboard-stats");
    const sectionTitle = document.querySelector("#tab-dashboard h3");
    const personalTitle = document.querySelector("#personal-status-box h3");
    if (sectionTitle) sectionTitle.innerHTML = `<i class="fa-solid fa-kaaba text-emerald-600"></i> Kemajuan Kelompok Tahap Aktif`;
    if (personalTitle) personalTitle.innerHTML = `<i class="fa-solid fa-chart-line text-emerald-600"></i> Status Tabungan Anda`;

    // Hitung total tabungan terkumpul global
    const totalSakuGlobal = appState.data.setoran.reduce((sum, d) => sum + Number(d.jumlah), 0);
    const totalShohibul = appState.data.anggota.length;
    const totalGroup = appState.data.kelompok.length;
    const activeStage = appState.data.tahap.find(t => t.status === "Aktif")?.nama || "Tidak Ada";

    containerStats.innerHTML = `
      <div class="bg-gradient-to-br from-emerald-600 to-emerald-800 text-white p-5 rounded-2xl shadow-sm space-y-2">
        <span class="text-[10px] text-emerald-200 font-bold uppercase tracking-wider">Total Tabungan Terkumpul</span>
        <h4 class="text-xl font-extrabold">${formatRupiah(totalSakuGlobal)}</h4>
        <p class="text-[10px] text-emerald-100 flex items-center gap-1"><i class="fa-solid fa-cloud"></i> Terintegrasi Real-time</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-slate-200/80 shadow-xs space-y-2">
        <span class="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Shohibul Terdaftar</span>
        <h4 class="text-xl font-extrabold text-slate-900">${totalShohibul} Jiwa</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1"><i class="fa-solid fa-users"></i> Anggota Keluarga</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-slate-200/80 shadow-xs space-y-2">
        <span class="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Kelompok Qurban</span>
        <h4 class="text-xl font-extrabold text-slate-900">${totalGroup} Kelompok</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1"><i class="fa-solid fa-cow"></i> Sapi & Kambing</p>
      </div>
      <div class="bg-white p-5 rounded-2xl border border-slate-200/80 shadow-xs space-y-2">
        <span class="text-[10px] text-slate-400 font-bold uppercase tracking-wider">Periode Tahap Aktif</span>
        <h4 class="text-sm font-extrabold text-emerald-700 truncate" title="${activeStage}">${activeStage}</h4>
        <p class="text-[10px] text-slate-500 flex items-center gap-1"><i class="fa-solid fa-calendar"></i> Periode Berjalan</p>
      </div>
    `;

    // Render Progress Kelompok
    const containerGroups = document.getElementById("dashboard-group-progress");
    containerGroups.innerHTML = "";

    if (appState.data.kelompok.length === 0) {
      containerGroups.innerHTML = "<p class='text-xs text-slate-400 italic col-span-2'>Belum ada kelompok qurban yang ditambahkan.</p>";
    } else {
      appState.data.kelompok.forEach(g => {
        // Cari semua anggota kelompok ini
        const members = appState.data.anggota.filter(a => a.kelompok_id === g.id);
        let groupTerkumpul = 0;
        members.forEach(m => {
          groupTerkumpul += getParticipantTotalSaving(m.id);
        });

        const pct = Math.min(Math.round((groupTerkumpul / g.target) * 100), 100);

        containerGroups.innerHTML += `
          <div class="bg-slate-50 p-4 rounded-xl border border-slate-100 space-y-3">
            <div class="flex justify-between items-center">
              <span class="font-bold text-xs text-slate-800">${g.nama}</span>
              <span class="text-[10px] bg-emerald-100 text-emerald-800 font-bold px-2 py-0.5 rounded-full">${g.tipe}</span>
            </div>
            <div class="space-y-1">
              <div class="flex justify-between text-[10px] text-slate-400 font-semibold">
                <span>Progress: ${pct}%</span>
                <span>Target: ${formatRupiah(g.target)}</span>
              </div>
              <div class="w-full bg-slate-200 rounded-full h-2">
                <div class="bg-emerald-600 h-2 rounded-full" style="width: ${pct}%"></div>
              </div>
            </div>
            <div class="flex justify-between text-[10px] text-slate-500">
              <span>Terkumpul: ${formatRupiah(groupTerkumpul)}</span>
              <span>${members.length} Shohibul</span>
            </div>
          </div>
        `;
      });
    }

    // Render Personal Card
    const personalBox = document.getElementById("personal-status-box");
    const cardDetails = document.getElementById("personal-card-details");

    if (isShohibulSession()) {
      const uObj = appState.user.data;
      const group = appState.data.kelompok.find(g => g.id === uObj.kelompok_id);
      const myTerkumpul = getParticipantTotalSaving(uObj.id);
      const target = uObj.target_saving || 3000000;
      const myPct = Math.min(Math.round((myTerkumpul / target) * 100), 100);

      cardDetails.innerHTML = `
        <div class="flex justify-between items-center border-b border-emerald-100 pb-2">
          <span class="text-xs text-emerald-900 font-bold">${uObj.nama}</span>
          <span class="text-[10px] bg-emerald-600 text-white font-bold px-2 py-0.5 rounded-md">${group ? group.nama : "Tanpa Kelompok"}</span>
        </div>
        <div class="grid grid-cols-2 gap-2 text-xs pt-1">
          <div>
            <p class="text-[10px] text-emerald-700/60 font-semibold">Target Tabungan</p>
            <p class="font-bold text-emerald-950">${formatRupiah(target)}</p>
          </div>
          <div>
            <p class="text-[10px] text-emerald-700/60 font-semibold">Dana Terkumpul</p>
            <p class="font-bold text-emerald-950">${formatRupiah(myTerkumpul)}</p>
          </div>
        </div>
        <div class="pt-2">
          <div class="flex justify-between text-[10px] text-emerald-700/80 font-bold mb-1">
            <span>Progres Pencapaian</span>
            <span>${myPct}%</span>
          </div>
          <div class="w-full bg-emerald-200/50 rounded-full h-2">
            <div class="bg-emerald-600 h-2 rounded-full" style="width: ${myPct}%"></div>
          </div>
        </div>
      `;
      personalBox.classList.remove("hidden");
    } else {
      // Jika admin, tampilkan pintasan rekap ringkas
      cardDetails.innerHTML = `
        <div class="text-center py-2 space-y-2">
          <div class="w-10 h-10 bg-emerald-100 rounded-full flex items-center justify-center text-emerald-800 mx-auto">
            <i class="fa-solid fa-user-shield"></i>
          </div>
          <p class="text-xs font-bold text-slate-800">Sesi Login Pengurus</p>
          <p class="text-[10px] text-slate-500 leading-relaxed">Anda memegang kendali penuh atas manipulasi database, pencatatan transaksi arisan, penambahan shohibul dan sinkronisasi.</p>
        </div>
      `;
      personalBox.classList.remove("hidden");
    }
  }

  // --- TAHAP TABLE ---
  function renderTahap() {
    const tbody = document.getElementById("tahap-table-body");
    tbody.innerHTML = "";

    appState.data.tahap.forEach(t => {
      const tr = document.createElement("tr");
      tr.className = "hover:bg-slate-50/50 transition";
      tr.innerHTML = `
        <td class="p-4 pl-6 font-semibold text-slate-500 text-xs">${t.id}</td>
        <td class="p-4 font-bold text-slate-800 text-xs">${t.nama}</td>
        <td class="p-4">
          <span class="px-2.5 py-0.5 rounded-full text-[10px] font-bold ${t.status === "Aktif" ? "bg-emerald-100 text-emerald-800" : "bg-slate-100 text-slate-600"}">
            ${t.status}
          </span>
        </td>
        <td class="p-4 pr-6 text-right no-print admin-only">
          <button class="text-emerald-600 hover:text-emerald-800 font-bold text-xs mr-3 transition" onclick="openEditTahap('${t.id}')">Edit</button>
          <button class="text-red-600 hover:text-red-800 font-bold text-xs transition" onclick="handleDeleteTahap('${t.id}')">Hapus</button>
        </td>
      `;
      tbody.appendChild(tr);
    });
  }

  // --- KELOMPOK TABLE ---
  function renderKelompok() {
    const tbody = document.getElementById("group-table-body");
    tbody.innerHTML = "";

    appState.data.kelompok.forEach(g => {
      const countAnggota = appState.data.anggota.filter(a => a.kelompok_id === g.id).length;
      const tr = document.createElement("tr");
      tr.className = "hover:bg-slate-50/50 transition";
      tr.innerHTML = `
        <td class="p-4 pl-6 font-bold text-slate-800 text-xs">${g.nama}</td>
        <td class="p-4"><span class="bg-slate-100 px-2 py-0.5 rounded-md text-[10px] font-bold text-slate-600">${g.tipe}</span></td>
        <td class="p-4 font-semibold text-slate-700 text-xs">${formatRupiah(g.target)}</td>
        <td class="p-4 font-semibold text-slate-700 text-xs">${countAnggota} Shohibul</td>
        <td class="p-4 pr-6 text-right no-print admin-only">
          <button class="text-emerald-600 hover:text-emerald-800 font-bold text-xs mr-3 transition" onclick="openEditGroup('${g.id}')">Edit</button>
          <button class="text-red-600 hover:text-red-800 font-bold text-xs transition" onclick="handleDeleteGroup('${g.id}')">Hapus</button>
        </td>
      `;
      tbody.appendChild(tr);
    });
  }

  // --- ANGGOTA TABLE ---
  function renderParticipants() {
    const query = document.getElementById("participant-search").value.toLowerCase();
    const tbody = document.getElementById("participant-table-body");
    tbody.innerHTML = "";

    const filtered = sortByNameAsc(appState.data.anggota).filter(a => 
      a.nama.toLowerCase().includes(query) || (a.whatsapp && a.whatsapp.includes(query))
    );

    filtered.forEach((a, index) => {
      const group = appState.data.kelompok.find(g => g.id === a.kelompok_id);
      const tr = document.createElement("tr");
      tr.className = "hover:bg-slate-50/50 transition";
      tr.innerHTML = `
        <td class="p-4 pl-6 text-center font-bold text-slate-500 text-xs">${index + 1}</td>
        <td class="p-4 font-bold text-slate-800 text-xs">${a.nama}</td>
        <td class="p-4 text-slate-500 text-xs font-medium">${a.whatsapp || "-"}</td>
        <td class="p-4 text-slate-500 font-mono text-xs font-semibold">${a.pin || "1234"}</td>
        <td class="p-4 text-slate-700 text-xs font-semibold">${group ? group.nama : "<span class='text-slate-400 italic font-normal'>Mandiri</span>"}</td>
        <td class="p-4 text-emerald-800 font-bold text-xs">${formatRupiah(a.target_saving)}</td>
        <td class="p-4 pr-6 text-right no-print admin-only">
          <button class="text-emerald-600 hover:text-emerald-800 font-bold text-xs mr-3 transition" onclick="openEditParticipant('${a.id}')">Edit</button>
          <button class="text-red-600 hover:text-red-800 font-bold text-xs transition" onclick="handleDeleteParticipant('${a.id}')">Hapus</button>
        </td>
      `;
      tbody.appendChild(tr);
    });
  }

  // --- SETORAN TABLE ---
  function renderDeposits() {
    const query = document.getElementById("deposit-search").value.toLowerCase();
    const tbody = document.getElementById("deposit-table-body");
    const pageSizeSelect = document.getElementById("deposit-page-size");
    tbody.innerHTML = "";
    if (pageSizeSelect && Number(pageSizeSelect.value) !== appState.depositPageSize) {
      pageSizeSelect.value = String(appState.depositPageSize);
    }

    // Filter transaksi
    const filtered = appState.data.setoran.filter(d => {
      const owner = appState.data.anggota.find(a => a.id === d.anggota_id);
      return (
        (owner && owner.nama.toLowerCase().includes(query)) ||
        d.recorded_by.toLowerCase().includes(query) ||
        (d.catatan && d.catatan.toLowerCase().includes(query))
      );
    });

    // Data terbaru di atas: tanggal setor terbaru, lalu update terbaru, lalu bulan terbesar.
    filtered.sort((a, b) => {
      const dateDiff = parseDepositDate(b.tanggal) - parseDepositDate(a.tanggal);
      if (dateDiff !== 0) return dateDiff;
      const updateDiff = Number(b.updatedAt || 0) - Number(a.updatedAt || 0);
      if (updateDiff !== 0) return updateDiff;
      return Number(b.bulan || 0) - Number(a.bulan || 0);
    });

    const totalRows = filtered.length;
    const totalPages = Math.max(1, Math.ceil(totalRows / appState.depositPageSize));
    appState.depositPage = Math.min(Math.max(1, appState.depositPage), totalPages);
    const startIndex = (appState.depositPage - 1) * appState.depositPageSize;
    const pageRows = filtered.slice(startIndex, startIndex + appState.depositPageSize);

    if (pageRows.length === 0) {
      const tr = document.createElement("tr");
      tr.innerHTML = `<td class="p-6 text-center text-xs text-slate-400 font-semibold" colspan="8">Tidak ada data setoran yang cocok.</td>`;
      tbody.appendChild(tr);
    }

    pageRows.forEach((d, index) => {
      const owner = appState.data.anggota.find(a => a.id === d.anggota_id);
      const tr = document.createElement("tr");
      tr.className = "hover:bg-slate-50/50 transition";
      tr.innerHTML = `
        <td class="p-4 pl-6 text-center font-bold text-slate-500 text-xs">${startIndex + index + 1}</td>
        <td class="p-4 font-semibold text-slate-500 text-xs">${formatDepositDate(d.tanggal)}</td>
        <td class="p-4 font-bold text-slate-800 text-xs">${owner ? owner.nama : "Tidak Diketahui"}</td>
        <td class="p-4 font-semibold text-slate-700 text-xs">Bulan Ke-${d.bulan}</td>
        <td class="p-4 text-emerald-800 font-extrabold text-xs">${formatRupiah(d.jumlah)}</td>
        <td class="p-4 text-slate-700 text-xs font-medium">${d.recorded_by}</td>
        <td class="p-4 text-slate-400 text-xs italic max-w-[150px] truncate" title="${d.catatan || ''}">${d.catatan || "-"}</td>
        <td class="p-4 pr-6 text-right no-print admin-only">
          <button class="text-emerald-600 hover:text-emerald-800 font-bold text-xs mr-3 transition" onclick="openEditDeposit('${d.id}')">Edit</button>
          <button class="text-red-600 hover:text-red-800 font-bold text-xs transition" onclick="handleDeleteDeposit('${d.id}')">Hapus</button>
        </td>
      `;
      tbody.appendChild(tr);
    });

    renderDepositPagination(totalRows, totalPages, startIndex, pageRows.length);
  }

  function resetDepositPagination() {
    appState.depositPage = 1;
    renderDeposits();
  }

  function changeDepositPageSize(value) {
    appState.depositPageSize = Number(value) || 10;
    appState.depositPage = 1;
    renderDeposits();
  }

  function goToDepositPage(page) {
    appState.depositPage = page;
    renderDeposits();
  }

  function renderDepositPagination(totalRows, totalPages, startIndex, currentCount) {
    const info = document.getElementById("deposit-page-info");
    const controls = document.getElementById("deposit-pagination-controls");
    if (!info || !controls) return;

    if (totalRows === 0) {
      info.innerText = "Menampilkan 0 data";
    } else {
      info.innerText = `Menampilkan ${startIndex + 1}-${startIndex + currentCount} dari ${totalRows} data`;
    }

    const buttonBase = "h-9 min-w-9 px-3 rounded-xl border text-xs font-bold transition";
    const disabledPrev = appState.depositPage <= 1;
    const disabledNext = appState.depositPage >= totalPages;
    const pages = [];
    const firstPage = Math.max(1, appState.depositPage - 2);
    const lastPage = Math.min(totalPages, appState.depositPage + 2);
    for (let page = firstPage; page <= lastPage; page++) pages.push(page);

    controls.innerHTML = `
      <button class="${buttonBase} ${disabledPrev ? "border-slate-100 text-slate-300 cursor-not-allowed" : "border-slate-200 text-slate-600 hover:border-emerald-300 hover:text-emerald-700"}" ${disabledPrev ? "disabled" : ""} onclick="goToDepositPage(${appState.depositPage - 1})" type="button">Prev</button>
      ${pages.map(page => `<button class="${buttonBase} ${page === appState.depositPage ? "border-emerald-600 bg-emerald-600 text-white" : "border-slate-200 text-slate-600 hover:border-emerald-300 hover:text-emerald-700"}" onclick="goToDepositPage(${page})" type="button">${page}</button>`).join("")}
      <button class="${buttonBase} ${disabledNext ? "border-slate-100 text-slate-300 cursor-not-allowed" : "border-slate-200 text-slate-600 hover:border-emerald-300 hover:text-emerald-700"}" ${disabledNext ? "disabled" : ""} onclick="goToDepositPage(${appState.depositPage + 1})" type="button">Next</button>
    `;
  }

  // --- REKAP MATRIX RENDERING (BULAN 1 - 12) ---
  function parseDepositDate(value) {
    const rawDate = String(value || "").trim();
    if (!rawDate) return "";

    const isoDate = rawDate.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);
    if (isoDate) {
      return new Date(Number(isoDate[1]), Number(isoDate[2]) - 1, Number(isoDate[3]));
    }

    const dayMonthYear = rawDate.match(/^(\d{1,2})[\/\-.](\d{1,2})[\/\-.](\d{4})$/);
    if (dayMonthYear) {
      return new Date(Number(dayMonthYear[3]), Number(dayMonthYear[2]) - 1, Number(dayMonthYear[1]));
    }

    const parsedDate = new Date(rawDate);
    return Number.isNaN(parsedDate.getTime()) ? "" : parsedDate;
  }

  function formatDateShortId(date) {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return "";
    const day = String(date.getDate()).padStart(2, "0");
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const year = String(date.getFullYear());
    return `${day}/${month}/${year}`;
  }

  function formatDateDashId(date) {
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return "";
    const day = String(date.getDate()).padStart(2, "0");
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const year = String(date.getFullYear());
    return `${day}-${month}-${year}`;
  }

  function formatDepositDate(value) {
    const date = parseDepositDate(value);
    return date ? formatDateDashId(date) : String(value || "");
  }

  function toDateInputValue(value) {
    const date = parseDepositDate(value);
    if (!(date instanceof Date) || Number.isNaN(date.getTime())) return "";
    const day = String(date.getDate()).padStart(2, "0");
    const month = String(date.getMonth() + 1).padStart(2, "0");
    const year = String(date.getFullYear());
    return `${year}-${month}-${day}`;
  }

  function getRekapMonthDate(month) {
    const dates = appState.data.setoran
      .filter(d => Number(d.bulan) === month)
      .map(d => parseDepositDate(d.tanggal))
      .filter(date => date instanceof Date && !Number.isNaN(date.getTime()))
      .sort((a, b) => a - b);

    return dates.length ? formatDateShortId(dates[0]) : "";
  }

  function escapeHtml(value) {
    return String(value ?? "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#039;");
  }

  function renderRekapHeader() {
    const thead = document.getElementById("rekap-table-head");
    if (!thead) return;
    const monthHeaders = Array.from({ length: 12 }, (_, i) => {
      const month = i + 1;
      const date = getRekapMonthDate(month);
      return `
        <th class="p-2 border-r border-slate-100 align-middle">
          <span class="block text-[11px] font-extrabold text-slate-700">B${month}</span>
          <span class="block text-[9px] font-semibold text-emerald-600 mt-0.5">${date ? escapeHtml(date) : "-"}</span>
        </th>
      `;
    }).join("");
    thead.innerHTML = `
      <tr class="text-slate-600 font-bold border-b border-slate-200 bg-slate-50/80">
        <th class="p-3 border-r border-slate-200/60 w-14">No</th>
        <th class="p-3 text-left border-r border-slate-200/60 min-w-[180px]">Nama Shohibul</th>
        ${monthHeaders}
        <th class="p-3 font-semibold bg-emerald-50 text-emerald-800 rounded-tr-xl">Total Saku</th>
      </tr>
    `;
  }

  function getRekapMonthAmount(anggotaId, month) {
    const matchedDeposit = appState.data.setoran.find(d => d.anggota_id === anggotaId && Number(d.bulan) === month);
    return matchedDeposit ? Number(matchedDeposit.jumlah || 0) : 0;
  }

  function renderRekap() {
    renderRekapHeader();
    const tbody = document.getElementById("rekap-table-body");
    tbody.innerHTML = "";

    const sourceAnggota = isShohibulSession()
      ? appState.data.anggota.filter(a => a.id === appState.user.data.id)
      : appState.data.anggota;
    const sortedAnggota = sortByNameAsc(sourceAnggota);

    sortedAnggota.forEach((a, index) => {
      const tr = document.createElement("tr");
      tr.className = "hover:bg-slate-50/50 transition";

      let rowHtml = `<td class="p-3 text-center font-bold text-slate-500 border-r border-slate-200/60 text-xs">${index + 1}</td><td class="p-3 text-left font-bold text-slate-800 border-r border-slate-200/60 text-xs">${a.nama}</td>`;
      let memberTotal = 0;

      for (let b = 1; b <= 12; b++) {
        const amount = getRekapMonthAmount(a.id, b);
        if (amount > 0) {
          memberTotal += amount;
          rowHtml += `<td class="p-3 border-r border-slate-100 text-[10px] font-bold text-emerald-700 bg-emerald-50/40" title="Setor: ${formatRupiah(amount)}">&#10003;</td>`;
        } else {
          rowHtml += `<td class="p-3 border-r border-slate-100 text-[10px] text-slate-300 font-semibold">-</td>`;
        }
      }

      rowHtml += `<td class="p-3 font-extrabold bg-emerald-50 text-emerald-800 text-xs">${formatRupiah(memberTotal)}</td>`;
      tr.innerHTML = rowHtml;
      tbody.appendChild(tr);
    });
  }

  function getRekapRows() {
    const sourceAnggota = isShohibulSession()
      ? appState.data.anggota.filter(a => a.id === appState.user.data.id)
      : appState.data.anggota;

    return sortByNameAsc(sourceAnggota)
      .map((anggota, index) => {
        const depositsByMonth = {};
        let total = 0;
        for (let month = 1; month <= 12; month++) {
          const amount = getRekapMonthAmount(anggota.id, month);
          depositsByMonth[month] = amount;
          total += amount;
        }
        return { no: index + 1, anggota, depositsByMonth, total };
      });
  }

  function buildRekapReportHtml() {
    const rows = getRekapRows();
    const totalSetoran = rows.reduce((sum, row) => sum + row.total, 0);
    const printedAt = new Date().toLocaleDateString("id-ID", { day: "2-digit", month: "long", year: "numeric" });
    const ketua = appState.settings.ketuaName || "Ketua Arisan";
    const bendahara = appState.settings.bendaharaName || "Bendahara Arisan";
    const activeStage = appState.data.tahap.find(t => t.status === "Aktif")?.nama || "Periode Aktif";
    const nominalArisan = Number(appState.settings.monthlyInstallment || 150000);
    const headerCells = Array.from({ length: 12 }, (_, i) => {
      const month = i + 1;
      const date = getRekapMonthDate(month);
      return `<th><span>B${month}</span><small>${date ? escapeHtml(date) : "-"}</small></th>`;
    }).join("");
    const bodyRows = rows.map(row => {
      const monthCells = Array.from({ length: 12 }, (_, i) => {
        const amount = row.depositsByMonth[i + 1];
        return `<td class="month-cell ${amount > 0 ? "paid" : "empty"}">${amount > 0 ? formatRupiah(amount) : "-"}</td>`;
      }).join("");
      return `<tr><td class="num">${row.no}</td><td class="name">${escapeHtml(row.anggota.nama)}</td>${monthCells}<td class="total">${formatRupiah(row.total)}</td></tr>`;
    }).join("");

    return `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Laporan Rekap Setoran QurbanKu</title><style>
      @page { size: A4 landscape; margin: 12mm; }
      * { box-sizing: border-box; }
      body { font-family: Arial, sans-serif; color: #0f172a; margin: 0; font-size: 11px; }
      .letterhead { display: flex; justify-content: space-between; align-items: flex-start; border-bottom: 3px solid #047857; padding-bottom: 12px; margin-bottom: 14px; }
      .brand h1 { margin: 0 0 4px; font-size: 22px; color: #065f46; }
      .brand p { margin: 2px 0; color: #475569; }
      .meta { text-align: right; color: #475569; line-height: 1.5; }
      .summary { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin: 12px 0 14px; }
      .box { border: 1px solid #cbd5e1; padding: 8px; border-radius: 6px; }
      .box span { display: block; color: #64748b; font-size: 9px; text-transform: uppercase; font-weight: 700; margin-bottom: 4px; }
      .box strong { font-size: 13px; color: #064e3b; }
      table { width: 100%; border-collapse: collapse; table-layout: fixed; }
      th, td { border: 1px solid #cbd5e1; padding: 5px 4px; text-align: center; vertical-align: middle; }
      th { background: #ecfdf5; color: #064e3b; font-size: 10px; }
      th small { display: block; color: #047857; font-size: 8px; margin-top: 2px; }
      .num { width: 28px; }
      .name { text-align: left; width: 145px; font-weight: 700; }
      .month-cell { font-size: 9px; }
      .paid { color: #047857; font-weight: 700; background: #f0fdf4; }
      .empty { color: #94a3b8; }
      .total { width: 82px; font-weight: 700; background: #f8fafc; color: #064e3b; }
      .signatures { display: grid; grid-template-columns: 1fr 1fr; gap: 80px; margin-top: 28px; text-align: center; page-break-inside: avoid; }
      .signature-title { margin-bottom: 58px; color: #334155; }
      .signature-name { font-weight: 700; border-top: 1px solid #0f172a; display: inline-block; min-width: 180px; padding-top: 5px; }
    </style></head><body>
      <div class="letterhead"><div class="brand"><h1>QurbanKu</h1><p>Manajemen Tabungan dan Arisan Qurban Keluarga</p><p>${escapeHtml(activeStage)}</p></div><div class="meta"><strong>Laporan Rekap Setoran</strong><br>Dicetak: ${printedAt}<br>Nominal Arisan: ${formatRupiah(nominalArisan)}</div></div>
      <div class="summary"><div class="box"><span>Total Shohibul</span><strong>${rows.length} Orang</strong></div><div class="box"><span>Total Setoran</span><strong>${formatRupiah(totalSetoran)}</strong></div><div class="box"><span>Sudah Setor B1</span><strong>${rows.filter(row => row.depositsByMonth[1] > 0).length} Orang</strong></div><div class="box"><span>Nominal Bulanan</span><strong>${formatRupiah(nominalArisan)}</strong></div></div>
      <table><thead><tr><th>No</th><th>Nama Shohibul</th>${headerCells}<th>Total</th></tr></thead><tbody>${bodyRows}</tbody></table>
      <div class="signatures"><div><div class="signature-title">Ketua Arisan</div><div class="signature-name">${escapeHtml(ketua)}</div></div><div><div class="signature-title">Bendahara Arisan</div><div class="signature-name">${escapeHtml(bendahara)}</div></div></div>
    </body></html>`;
  }

  function printRekapReport() {
    const printWindow = window.open("", "_blank", "width=1200,height=800");
    if (!printWindow) {
      showToast("Popup cetak diblokir browser. Izinkan popup untuk mencetak laporan.", "error");
      return;
    }
    printWindow.document.open();
    printWindow.document.write(buildRekapReportHtml());
    printWindow.document.close();
    printWindow.focus();
    setTimeout(() => printWindow.print(), 400);
  }

  function exportRekapExcel() {
    const rows = getRekapRows();
    const headerCells = Array.from({ length: 12 }, (_, i) => {
      const month = i + 1;
      const date = getRekapMonthDate(month);
      return `<th>B${month}${date ? " (" + escapeHtml(date) + ")" : ""}</th>`;
    }).join("");
    const bodyRows = rows.map(row => {
      const monthCells = Array.from({ length: 12 }, (_, i) => `<td>${row.depositsByMonth[i + 1] || 0}</td>`).join("");
      return `<tr><td>${row.no}</td><td>${escapeHtml(row.anggota.nama)}</td>${monthCells}<td>${row.total}</td></tr>`;
    }).join("");
    const excelHtml = `<html><head><meta charset="UTF-8"></head><body><table border="1"><tr><th colspan="15">Laporan Rekap Setoran QurbanKu</th></tr><tr><th>No</th><th>Nama Shohibul</th>${headerCells}<th>Total</th></tr>${bodyRows}</table></body></html>`;
    const blob = new Blob([excelHtml], { type: "application/vnd.ms-excel;charset=utf-8" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    link.href = url;
    link.download = `rekap-setoran-qurbanku-${new Date().toISOString().slice(0, 10)}.xls`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
    showToast("File Excel rekap setoran berhasil dibuat.", "success");
  }

  // --- SETTINGS RENDERING ---
  function renderSettings() {
    const displayUrl = document.getElementById("settings-gas-url-display");
    displayUrl.value = getActiveGasUrl();

    const ketuaInput = document.getElementById("settings-ketua-name");
    const bendaharaInput = document.getElementById("settings-bendahara-name");
    const installmentInput = document.getElementById("settings-monthly-installment");
    if (ketuaInput) ketuaInput.value = appState.settings.ketuaName || "";
    if (bendaharaInput) bendaharaInput.value = appState.settings.bendaharaName || "";
    if (installmentInput) installmentInput.value = appState.settings.monthlyInstallment || 150000;

    const pillContainer = document.getElementById("status-mode-preview-pill");
    if (IS_PREVIEW) {
      pillContainer.innerHTML = `<span class="px-2.5 py-1 text-[10px] font-extrabold rounded-lg bg-amber-100 text-amber-800 border border-amber-200 uppercase tracking-wider">Mode Preview (Lokal)</span>`;
    } else {
      pillContainer.innerHTML = `<span class="px-2.5 py-1 text-[10px] font-extrabold rounded-lg bg-emerald-100 text-emerald-800 border border-emerald-200 uppercase tracking-wider">Mode Produksi (Cloud)</span>`;
    }
  }

  function handleCloudUrlSubmit(event) {
    event.preventDefault();
    const input = document.getElementById("settings-gas-url-display");
    const newUrl = input.value.trim();

    if (!/^https:\/\/script\.google\.com\/macros\/s\/.+\/exec$/.test(newUrl)) {
      showToast("URL harus berupa Web App Google Apps Script dan berakhiran /exec.", "error");
      return;
    }

    if (IS_PREVIEW) {
      activeGasUrl = newUrl;
      renderSettings();
      showToast("URL tersimpan untuk mode preview saat ini.", "info");
      return;
    }

    showLoading(true, "Menyimpan URL Cloud...", "Menyimpan konfigurasi ke Google Sheet...");
    const currentUrl = getActiveGasUrl();
    activeGasUrl = newUrl;
    const requestPayload = JSON.stringify({
      action: "saveCloudUrl",
      data: { cloudUrl: newUrl },
      settings: { cloudUrl: newUrl }
    });

    requestCloud({ action: "sync", data: requestPayload })
      .then((response) => {
        if (response.status !== "success") {
          throw new Error(response.message || "Server tidak mengonfirmasi penyimpanan URL.");
        }
        activeGasUrl = newUrl;
        localStorage.setItem("qurbankuGasUrl", newUrl);
        applyCloudSettings(response);
        appState.data = normalizeCloudData(response);
        afterDataLoaded();
        setCloudIndicator("online");
        renderSettings();
        showToast("URL Google Apps Script tersimpan permanen di Google Sheet.", "success");
      })
      .catch((err) => {
        console.error("Gagal menyimpan URL cloud:", err);
        activeGasUrl = currentUrl;
        input.value = currentUrl;
        showToast("Gagal menyimpan URL. Pastikan URL baru benar, sudah di-deploy sebagai Web App, dan aksesnya Anyone.", "error");
      })
      .finally(() => {
        showLoading(false);
      });
  }

  function handleArisanSettingsSubmit(event) {
    event.preventDefault();
    const payload = {
      ketuaName: document.getElementById("settings-ketua-name").value.trim(),
      bendaharaName: document.getElementById("settings-bendahara-name").value.trim(),
      monthlyInstallment: Number(document.getElementById("settings-monthly-installment").value || 0)
    };

    if (!payload.ketuaName || !payload.bendaharaName || payload.monthlyInstallment <= 0) {
      showToast("Ketua, bendahara, dan nominal arisan wajib diisi.", "error");
      return;
    }

    showLoading(true, "Menyimpan Pengaturan...", "Mengirim data ketua, bendahara, dan nominal arisan...");
    const requestPayload = JSON.stringify({ action: "saveSettings", data: payload, settings: payload });
    requestCloud({ action: "sync", data: requestPayload })
      .then((response) => {
        if (response.status !== "success") {
          throw new Error(response.message || "Server tidak mengonfirmasi penyimpanan pengaturan.");
        }
        applyCloudSettings(response);
        appState.data = normalizeCloudData(response);
        appState.settings = { ...appState.settings, ...payload };
        afterDataLoaded();
        setCloudIndicator("online");
        renderSettings();
        showToast("Pengaturan arisan berhasil disimpan.", "success");
      })
      .catch((err) => {
        console.error("Gagal menyimpan pengaturan arisan:", err);
        setCloudIndicator("error");
        showToast("Gagal menyimpan pengaturan arisan ke Google Sheet.", "error");
      })
      .finally(() => {
        showLoading(false);
      });
  }

