  function handleParticipantSubmit(event) {
    event.preventDefault();
    const id = document.getElementById("edit-participant-id").value;
    const payload = {
      id: id || "",
      nama: document.getElementById("participant-name").value.trim(),
      whatsapp: document.getElementById("participant-whatsapp").value.trim(),
      pin: document.getElementById("participant-pin").value.trim(),
      kelompok_id: document.getElementById("participant-group").value,
      target_saving: Number(document.getElementById("participant-target").value)
    };

    sendCloudWrite("saveAnggota", payload).then(() => {
      closeModal("anggota-modal");
    });
  }

  function handleDeleteParticipant(id) {
    showConfirm("Hapus Shohibul", "Menghapus shohibul akan merusak keharmonisan data rekap. Yakin?", () => {
      sendCloudWrite("deleteAnggota", { id: id });
    });
  }

  // --- ACTIONS FOR SETORAN (DEPOSIT) ---
  function openAddDeposit() {
    document.getElementById("setoran-modal-title").innerText = "Input Setoran Tabungan";
    document.getElementById("edit-deposit-id").value = "";
    document.getElementById("deposit-participant").value = "";
    document.getElementById("deposit-date").value = toDateInputValue(new Date());
    document.getElementById("deposit-amount").value = "";
    document.getElementById("deposit-recorded").value = appState.user.data.nama;
    document.getElementById("deposit-note").value = "";

    // Auto pilih bulan terkecil yang belum lunas
    document.getElementById("deposit-bulan").value = "1";
    openModal("setoran-modal");
  }

  function openEditDeposit(id) {
    const d = appState.data.setoran.find(x => x.id === id);
    if (!d) return;
    document.getElementById("setoran-modal-title").innerText = "Edit Setoran Tabungan";
    document.getElementById("edit-deposit-id").value = d.id;
    document.getElementById("deposit-participant").value = d.anggota_id;
    document.getElementById("deposit-date").value = toDateInputValue(d.tanggal);
    document.getElementById("deposit-amount").value = formatNumberGroup(d.jumlah);
    document.getElementById("deposit-bulan").value = d.bulan;
    document.getElementById("deposit-recorded").value = d.recorded_by;
    document.getElementById("deposit-note").value = d.catatan || "";
    openModal("setoran-modal");
  }

  function handleDepositSubmit(event) {
    event.preventDefault();
    const id = document.getElementById("edit-deposit-id").value;
    const payload = {
      id: id || "",
      anggota_id: document.getElementById("deposit-participant").value,
      tanggal: formatDepositDate(document.getElementById("deposit-date").value),
      jumlah: parseMoneyInput(document.getElementById("deposit-amount").value),
      bulan: Number(document.getElementById("deposit-bulan").value),
      recorded_by: document.getElementById("deposit-recorded").value.trim(),
      catatan: document.getElementById("deposit-note").value.trim()
    };

    sendCloudWrite("saveSetoran", payload).then(() => {
      closeModal("setoran-modal");
    });
  }

  function handleDeleteDeposit(id) {
    showConfirm("Hapus Transaksi", "Yakin ingin membatalkan transaksi pencatatan ini?", () => {
      sendCloudWrite("deleteSetoran", { id: id });
    });
  }

  // =========================================================================
  // MODAL DIALOG CONFIRM & SYSTEM TOASTS
  // =========================================================================
  let confirmCallback = null;

  function showConfirm(title, message, callback) {
    document.getElementById("modal-title").innerText = title;
    document.getElementById("modal-message").innerText = message;
    document.getElementById("confirm-modal").classList.remove("hidden");
    confirmCallback = callback;
  }

  document.getElementById("modal-btn-cancel").addEventListener("click", () => {
    document.getElementById("confirm-modal").classList.add("hidden");
    confirmCallback = null;
  });

  document.getElementById("modal-btn-confirm").addEventListener("click", () => {
    document.getElementById("confirm-modal").classList.add("hidden");
    if (confirmCallback) {
      confirmCallback();
    }
  });

  function showToast(message, type = "success") {
    const container = document.getElementById("toast-container");
    const toast = document.createElement("div");

    let icon = "fa-circle-check";
    let colorClass = "bg-emerald-50 border-emerald-100 text-emerald-800";

    if (type === "error") {
      icon = "fa-circle-exclamation";
      colorClass = "bg-red-50 border-red-100 text-red-800";
    } else if (type === "info") {
      icon = "fa-circle-info";
      colorClass = "bg-blue-50 border-blue-100 text-blue-800";
    }

    toast.className = `flex items-center gap-2.5 px-4 py-3 rounded-2xl shadow-lg border text-xs font-semibold pointer-events-auto transition duration-300 transform translate-y-2 opacity-0 ${colorClass}`;
    toast.innerHTML = `<i class="fa-solid ${icon}"></i> <span>${message}</span>`;

    container.appendChild(toast);

    // Animate In
    setTimeout(() => {
      toast.classList.remove("translate-y-2", "opacity-0");
    }, 50);

    // Dismiss Out
    setTimeout(() => {
      toast.classList.add("opacity-0", "translate-y-2");
      setTimeout(() => {
        toast.remove();
      }, 300);
    }, 4000);
  }
//
